* SQLD1 -- demo screen for the SQLD transaction. Operator types
* a customer ID; SQLD runs `SELECT name FROM customers_sql WHERE id = :K`
* into :NM and renders the row back here. SQLCODE / SQLSTATE / SQLERRMC
* land on the lower half so the operator can see what Postgres said.
MAP SQLD1 SIZE 24x80
  FIELD AT 0,2  LEN 30 PROT BRIGHT COLOR=BLUE  "Embedded SQL demo -- SQLD"
  FIELD AT 0,60 LEN 5  PROT COLOR=BLUE         "TERM="
  INPUT TERMID  AT 0,65 LEN 8  PROT COLOR=BLUE
  FIELD AT 4,4  LEN 50 PROT COLOR=BLUE         "Customer id (PIC X(10)):"
  INPUT CUSTID  AT 4,29 LEN 10 UNDERSCORE COLOR=GREEN
  STOP          AT 4,40
  FIELD AT 8,4  LEN 50 PROT                    "Name from customers_sql:"
  INPUT NM      AT 8,29 LEN 30 PROT COLOR=YELLOW
  FIELD AT 14,4 LEN 8  PROT                    "SQLCODE:"
  INPUT SQLCD   AT 14,13 LEN 8  PROT COLOR=TURQUOISE
  FIELD AT 15,4 LEN 9  PROT                    "SQLSTATE:"
  INPUT SQLST   AT 15,14 LEN 5  PROT COLOR=TURQUOISE
  FIELD AT 16,4 LEN 9  PROT                    "SQLERRMC:"
  INPUT SQLERR  AT 16,14 LEN 60 PROT BRIGHT COLOR=RED
  FIELD AT 22,2 LEN 60 PROT COLOR=BLUE         "ENTER=Query  PF3=Exit"
  CURSOR        AT 4,30
ENDMAP
